// Verify the Telnyx Ed25519 signature over `${timestamp}|${rawBody}`, reject
// stale/invalid webhooks, then normalize the event for downstream nodes.
const crypto = require('crypto');

const pubKeyB64 = $('Config').first().json.telnyx_public_key;
if (!pubKeyB64 || pubKeyB64.startsWith('<<')) {
  throw new Error('Config: telnyx_public_key is not set');
}

const item = $input.first();
const headers = item.json.headers || {};
const sigB64 = headers['telnyx-signature-ed25519'];
const timestamp = headers['telnyx-timestamp'];
if (!sigB64 || !timestamp) {
  throw new Error('Missing Telnyx signature headers');
}

// Raw body bytes exactly as Telnyx sent them (rawBody option on the Webhook node).
let rawBody;
if (item.binary && item.binary.data && item.binary.data.data) {
  rawBody = Buffer.from(item.binary.data.data, 'base64').toString('utf8');
} else if (typeof item.json.body === 'string') {
  rawBody = item.json.body;
} else {
  rawBody = JSON.stringify(item.json.body || {});
}

// Replay protection: reject anything older than 5 minutes.
const nowSec = Math.floor($now.toSeconds());
if (Math.abs(nowSec - parseInt(timestamp, 10)) > 300) {
  throw new Error('Stale webhook (timestamp outside 5 min window)');
}

// Ed25519 verify. Wrap the raw 32-byte public key in a DER SPKI header.
const rawKey = Buffer.from(pubKeyB64, 'base64');
const der = Buffer.concat([Buffer.from('302a300506032b6570032100', 'hex'), rawKey]);
const publicKey = crypto.createPublicKey({ key: der, format: 'der', type: 'spki' });
const signed = Buffer.from(`${timestamp}|${rawBody}`, 'utf8');
const ok = crypto.verify(null, signed, publicKey, Buffer.from(sigB64, 'base64'));
if (!ok) {
  throw new Error('Invalid Telnyx signature — discarding');
}

// Parse and normalize.
const event = JSON.parse(rawBody);
const p = (event.data && event.data.payload) || event.payload || {};
const eventType = (event.data && event.data.event_type) || event.event_type || '';

const toArr = Array.isArray(p.to) ? p.to : [];
const telnyxNumber = (toArr[0] && toArr[0].phone_number) || p.to || '';
const contactNumber = (p.from && p.from.phone_number) || p.from || '';

return [{
  json: {
    event_type: eventType,
    telnyx_message_id: p.id || null,
    telnyx_number: telnyxNumber,
    contact_number: contactNumber,
    body: p.text || '',
    media: (p.media && p.media.length) ? p.media : null,
    status: (Array.isArray(p.to) && p.to[0] && p.to[0].status) || p.status || null
  }
}];
